 25→function useLearnMoreRewardProgram(): UseLearnMoreRewardProgramReturn {
 26→  const route = useRoute();
 27→  const navigation = useNavigation();
 28→  const hasFocused = useRef(false);
 29→  const { width } = useWindowDimensions();
 30→  const { status, selectedCategory } = useRootStore(
 31→    state => state.parameterPointsProgram,
 32→  );
 33→
 34→  useScreenViewTracking({
 35→    route,
 36→    title: 'Saiba mais',
 37→  });
 38→
 39→  useFocusEffect(
 40→    useCallback(() => {
 41→      if (!hasFocused.current) {
 42→        eventScreenViewV3(
 43→          'saiba_mais',
 44→          'hub_recompensas_spmais',
 45→          'monetizacao',
 46→          {
 47→            location_1: 'monetizacao',
 48→            location_2: 'hub_recompensas_spmais',
 49→            location_3: 'saiba_mais',
 50→          },
 51→        );
 52→        hasFocused.current = true;
 53→      }
 54→      return () => {
 55→        hasFocused.current = false;
 56→      };
 57→    }, []),
 58→  );
 59→
 60→  const widthWithPaddingInnerLarger = Math.ceil(width - PADDING_INNER_LARGER);
 61→  const widthWithPaddingInnerLargerWithMargin =
 62→    widthWithPaddingInnerLarger - MARGIN_STANDING_XS;
 63→
 64→  const handleNavigation = () => {
 65→    navigation.goBack();
 66→  };
 67→
 68→  const items = useMemo((): propsItems[] => {
 69→    if (
 70→      typeof selectedCategory?.value === 'string' ||
 71→      !selectedCategory?.value?.questions ||
 72→      !selectedCategory?.category
 73→    ) {
 74→      return [];
 75→    }
 76→
 77→    return selectedCategory.value.questions.map((
 78→      item: {
 79→        question: string;
 80→        answer: string;
 81→      },
 82→      index: number,
 83→    ): propsItems => {
 84→      return {
 85→        id: index,
 86→        title: item.question,
 87→        text: item.answer,
 88→        titleColor: 'BRAND_COMPLEMENT_01',
 89→        headerIconName: (selectedCategory.value as ParameterPointsProgramValue)
 90→          .icon,
 91→        hasSecondaryParagraph: false,
 92→        hideSecondaryIconParagraph: true,
 93→        hideIcon: true,
 94→        onPressCard: () => {
 95→          eventSelectContent({
 96→            content_type: 'cta',
 97→            content_id: sanitizeTaxonomy(item.question),
 98→            location_1: 'monetizacao',
 99→            location_2: 'hub_recompensas_spmais',
100→            location_3: 'saiba_mais',
101→          });
102→        },
103→      } as propsItems;
104→    });
105→  }, [selectedCategory]);
106→
107→  const hasError =
108→    !selectedCategory ||
109→    typeof selectedCategory?.value === 'string' ||
110→    status === ParameterPointsProgramStatus.ERROR;
111→
112→  return {
113→    data: items,
114→    title: selectedCategory?.category || '',
115→    widthWithPaddingInnerLargerWithMargin,
116→    onNavigation: handleNavigation,
117→    hasError,
118→  };
119→}
120→
121→export default function LearnMoreRewardProgram() {
122→  const {
123→    data,
124→    title,
125→    widthWithPaddingInnerLargerWithMargin,
126→    onNavigation,
127→    hasError,
128→  } = useLearnMoreRewardProgram();
129→
130→  if (hasError) {
131→    return <ApiError onPress={onNavigation} />;
132→  }
133→
134→  return (
135→    <LearnMoreRewardProgramView
136→      data={data}
137→      title={title}
138→      widthWithPaddingInnerLargerWithMargin={
139→        widthWithPaddingInnerLargerWithMargin
140→      }
141→      onNavigation={onNavigation}
142→    />
143→  );
144→}
